from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize aggregations dictionary
    aggregations = defaultdict(lambda: {
        "count": 0,
        "total_score": 0.0,
        "max_score": float('-inf'),
        "min_score": float('inf')
    })

    # Add custom aggregation fields if provided
    if aggregation_funcs:
        for field_name in aggregation_funcs.keys():
            aggregations.default_factory = lambda: {
                **aggregations.default_factory(),
                field_name: None
            }

    # Iterate through each search result
    for result in search_results:
        # Extract group value from metadata
        group_value = result.metadata.get(group_by_field)

        # Handle missing group values
        if group_value is None or group_value == "":
            group_value = "unknown"

        # Update aggregation statistics
        group_data = aggregations[group_value]

        # Default statistics
        group_data["count"] += 1
        group_data["total_score"] += result.score
        if result.score > group_data["max_score"]:
            group_data["max_score"] = result.score
        if result.score < group_data["min_score"]:
            group_data["min_score"] = result.score

        # Custom aggregations
        if aggregation_funcs:
            for field_name, func in aggregation_funcs.items():
                # Get field value from result metadata
                field_value = result.metadata.get(field_name)

                # Handle numeric operations for score-related fields
                if field_name == "score" and field_value is not None:
                    try:
                        field_value = float(field_value)
                    except (ValueError, TypeError):
                        field_value = None

                # Apply aggregation function
                if field_value is not None:
                    current_value = group_data.get(field_name)
                    if current_value is None:
                        group_data[field_name] = func(field_value)
                    else:
                        # For functions that work on collections (like sum, max, min)
                        if func in [max, min]:
                            group_data[field_name] = func([current_value, field_value])
                        elif func == sum:
                            group_data[field_name] = current_value + field_value
                        else:
                            # For other functions, we'll use the last value
                            group_data[field_name] = func(field_value)
                else:
                    # If field value is missing, keep existing value or set to None
                    if group_data.get(field_name) is None:
                        group_data[field_name] = None

    # Convert defaultdict to regular dict and calculate averages
    final_result = {}
    for group_value, data in aggregations.items():
        # Calculate average score
        if data["count"] > 0:
            data["avg_score"] = data["total_score"] / data["count"]
        else:
            data["avg_score"] = 0.0

        # Remove the total_score field since it's no longer needed
        data.pop("total_score", None)

        final_result[group_value] = data

    return final_result
